proof_block:
// Pull both ensures-instantiations into the proof context so the disjoint
// triggers for `r1` and `r2` line up. The original ensures gives us:
//   abstractify_seq_of_cpackets_to_set_of_sht_packets(r_i@) == self_@.un_acked_messages(src@)
//   self_@.un_acked_messages(src@) == r_i@.map_values(|p: CPacket| p@).to_set()
// Re-asserting each one (Verus must verify them) makes z3 instantiate both
// `forall`s on the same abstract witness `self_@.un_acked_messages(src@)`.
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@) == self_@.un_acked_messages(src@));
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@) == self_@.un_acked_messages(src@));
assert(self_@.un_acked_messages(src@) == r1@.map_values(|p: CPacket| p@).to_set());
assert(self_@.un_acked_messages(src@) == r2@.map_values(|p: CPacket| p@).to_set());

// Transitivity through the common abstract value gives the cross-run
// equalities z3 needs for the determinism postcondition.
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@)
       == abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@));
assert(r1@.map_values(|p: CPacket| p@).to_set()
       == r2@.map_values(|p: CPacket| p@).to_set());

// Set extensionality (lex-clean form) closes the gap on the set-of-views
// projection that the determinism predicate compares.
assert(r1@.map_values(|p: CPacket| p@).to_set()
       =~= r2@.map_values(|p: CPacket| p@).to_set());
